import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { authAPI } from '../services/api';
import '../styles/Login.css';

const Login = () => {
  const [isCreateMode, setIsCreateMode] = useState(false);
  const [fullName, setFullName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setLoading(true);

    try {
      const response = await authAPI.login(email, password);
      const { token, email: userEmail, fullName, role } = response.data;
      
      // Store token
      localStorage.setItem('authToken', token);
      
      // Update context with user data including role
      login(userEmail, fullName, token, role || 'USER');
      
      // Redirect to admin dashboard if admin, otherwise to user dashboard
      if (role === 'ADMIN') {
        navigate('/admin');
      } else {
        navigate('/');
      }
    } catch (err) {
      const errorMessage = err.response?.data?.message || err.response?.data?.error || 'Login failed. Please try again.';
      setError(typeof errorMessage === 'string' ? errorMessage : 'Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setLoading(true);

    try {
      await authAPI.register({
        email,
        password,
        fullName,
        role: 'USER',
      });

      setSuccess('Account created successfully. Please log in with your new account.');
      setPassword('');
      setIsCreateMode(false);
    } catch (err) {
      const errorMessage = err.response?.data?.message || err.response?.data?.error || err.response?.data || 'Account creation failed. Please try again.';
      setError(typeof errorMessage === 'string' ? errorMessage : 'Account creation failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleLogin = () => {
    window.location.href = 'http://localhost:8080/api/oauth2/authorization/google';
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <h1>Smart Campus Hub</h1>
        <p>{isCreateMode ? 'Create your student/staff account' : 'Facilities & Maintenance Management System'}</p>

        {error && <div className="alert alert-error">{error}</div>}
        {success && <div className="alert alert-success">{success}</div>}

        <form onSubmit={isCreateMode ? handleRegister : handleLogin}>
          {isCreateMode && (
            <div className="form-group">
              <label htmlFor="fullName">Full Name</label>
              <input
                id="fullName"
                type="text"
                value={fullName}
                onChange={(e) => setFullName(e.target.value)}
                placeholder="Enter your full name"
                required
              />
            </div>
          )}

          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input
              id="email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              id="password"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              required
            />
          </div>

          {isCreateMode && (
            <div className="form-group">
              <label htmlFor="role">Role</label>
              <input
                id="role"
                type="text"
                value="USER"
                readOnly
                disabled
              />
            </div>
          )}

          <button type="submit" className="btn btn-primary" disabled={loading}>
            {loading ? (isCreateMode ? 'Creating account...' : 'Logging in...') : (isCreateMode ? 'Create Account' : 'Login')}
          </button>
        </form>

        <div className="divider">Or</div>

        <button className="btn-google" onClick={handleGoogleLogin} disabled={isCreateMode}>
          Sign in with Google
        </button>

        <button
          className="auth-switch"
          onClick={() => {
            setIsCreateMode(!isCreateMode);
            setError('');
            setSuccess('');
          }}
          type="button"
        >
          {isCreateMode ? 'Already have an account? Login' : 'No account? Create one'}
        </button>
      </div>
    </div>
  );
};

export default Login;
